#include <stdio.h>

int main() {
    int T, y;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &y) != 1) break;
        if ((y % 400 == 0) || ((y % 4 == 0) && (y % 100 != 0)))
            printf("YES\n");
        else
            printf("NO\n");
    }
    return 0;
}

